mapper.select:
SELECT m.meetingId, m.title, m.placeName, m.meetingDate, m.startTime, m.maxMembers, m.status, m.content, m.thumbnailImage, s.name sportName, CONCAT(r.sido," ",r.sigungu," ",COALESCE(r.dong,"")) regionName, ( SELECT COUNT(*) FROM meetingParticipants mp WHERE mp.meetingId=m.meetingId AND mp.status="APPROVED" ) approved_count FROM meetings m JOIN sports s ON m.sportId=s.sportId JOIN regions r ON m.regionId=r.regionId WHERE m.deletedAt IS NULL
AND m.sportId=#{sportId}
AND m.regionId=#{regionId}
AND m.status=#{status}
AND ( m.title LIKE CONCAT("%",#{keyword},"%") OR m.content LIKE CONCAT("%",#{keyword},"%") )
ORDER BY m.meetingDate ASC, m.startTime ASC

mapper.update:
UPDATE meetings
SET deleted_at=NOW()
WHERE meeting_id=#{meetingId}

UPDATE meetings
SET status=#{status}
WHERE meeting_id=#{meetingId}

mapper.select:
SELECT max_members
FROM meetings
WHERE meeting_id=#{meetingId}
